import{_ as l,o as e,c as a,a2 as r}from"./chunks/framework.Pywvta2k.js";const x=JSON.parse('{"title":"经典食疗原则","description":"","frontmatter":{},"headers":[],"relativePath":"tcm-data/07-食疗养生/01-经典食疗原则.md","filePath":"tcm-data/07-食疗养生/01-经典食疗原则.md","lastUpdated":1781084559000}'),i={name:"tcm-data/07-食疗养生/01-经典食疗原则.md"};function o(n,t,d,s,g,h){return e(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="经典食疗原则" tabindex="-1">经典食疗原则 <a class="header-anchor" href="#经典食疗原则" aria-label="Permalink to &quot;经典食疗原则&quot;">​</a></h1><blockquote><p>跨医家食疗养生要旨</p></blockquote><hr><h2 id="一、《黄帝内经》食疗基础" tabindex="-1">一、《黄帝内经》食疗基础 <a class="header-anchor" href="#一、《黄帝内经》食疗基础" aria-label="Permalink to &quot;一、《黄帝内经》食疗基础&quot;">​</a></h2><blockquote><p><strong>「毒药攻邪，五谷为养，五果为助，五畜为益，五菜为充，气味合而服之，以补精益气。」</strong>（素问·脏气法时论）</p></blockquote><p><strong>顺序很重要</strong>：</p><ol><li><strong>五谷为养</strong>（主食）→ 基础</li><li><strong>五果为助</strong>（水果）→ 辅助</li><li><strong>五畜为益</strong>（肉食）→ 补益</li><li><strong>五菜为充</strong>（蔬菜）→ 补充</li></ol><blockquote><p><strong>「谷肉果菜，食养尽之，无使过之，伤其正也。」</strong></p></blockquote><hr><h2 id="二、孙思邈食治论" tabindex="-1">二、孙思邈食治论 <a class="header-anchor" href="#二、孙思邈食治论" aria-label="Permalink to &quot;二、孙思邈食治论&quot;">​</a></h2><blockquote><p><strong>「夫为医者，当须先洞晓病源，知其所犯，以食治之，食疗不愈，然后命药。」</strong></p></blockquote><p>孙思邈强调<strong>食疗优先于药疗</strong>的原则。</p><hr><h2 id="三、李东垣脾胃调养" tabindex="-1">三、李东垣脾胃调养 <a class="header-anchor" href="#三、李东垣脾胃调养" aria-label="Permalink to &quot;三、李东垣脾胃调养&quot;">​</a></h2><blockquote><p><strong>「脾胃之气既伤，而元气亦不能充。」</strong></p></blockquote><p><strong>养脾要点</strong>：</p><ol><li>饮食有节（不暴饮暴食）</li><li>温食为主（不吃冰）</li><li>细嚼慢咽（减轻脾胃负担）</li><li>饭后散步（助消化）</li></ol><hr><h2 id="四、徐文兵饮食养生" tabindex="-1">四、徐文兵饮食养生 <a class="header-anchor" href="#四、徐文兵饮食养生" aria-label="Permalink to &quot;四、徐文兵饮食养生&quot;">​</a></h2><blockquote><p><strong>「食物是最好的药物。」</strong></p></blockquote><p>核心理念：</p><ol><li><strong>吃应季的食物</strong></li><li><strong>吃本地出产的食物</strong></li><li><strong>吃完整的食物</strong>（不吃精加工食品）</li><li><strong>温热吃</strong>（不吃冰）</li><li><strong>吃适合自己的食物</strong>（体质不同）</li></ol><hr><h2 id="五、黄元御-圆运动饮食观" tabindex="-1">五、黄元御/圆运动饮食观 <a class="header-anchor" href="#五、黄元御-圆运动饮食观" aria-label="Permalink to &quot;五、黄元御/圆运动饮食观&quot;">​</a></h2><p>根据&quot;一气周流&quot;理论：</p><ul><li><strong>春季</strong>：多吃芽菜、绿叶，助肝木升发</li><li><strong>夏季</strong>：清淡、多汁，助心火下降</li><li><strong>长夏</strong>：健脾祛湿（薏米、山药、茯苓）</li><li><strong>秋季</strong>：润肺收敛（梨、百合、银耳）</li><li><strong>冬季</strong>：温补肾阳（羊肉、核桃、黑芝麻）</li></ul><hr><h2 id="六、普光-普明专属饮食建议" tabindex="-1">六、普光/普明专属饮食建议 <a class="header-anchor" href="#六、普光-普明专属饮食建议" aria-label="Permalink to &quot;六、普光/普明专属饮食建议&quot;">​</a></h2><h3 id="通用原则" tabindex="-1">通用原则 <a class="header-anchor" href="#通用原则" aria-label="Permalink to &quot;通用原则&quot;">​</a></h3><ul><li>✅ 温热饮食（粥、汤、炖菜）</li><li>✅ 发酵食物（馒头、面包、泡菜）→ 助消化</li><li>✅ 红茶、熟普 → 性温，适合寒湿体质</li><li>❌ 生冷寒凉（冰饮、生菜沙拉、凉拌菜）</li><li>❌ 大量水果（水果多寒凉）</li><li>❌ 油腻厚味（加重湿浊）</li></ul><h3 id="普光-阳虚寒湿-特别推荐" tabindex="-1">普光（阳虚寒湿）特别推荐 <a class="header-anchor" href="#普光-阳虚寒湿-特别推荐" aria-label="Permalink to &quot;普光（阳虚寒湿）特别推荐&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">食材</th><th style="text-align:left;">功效</th><th style="text-align:left;">建议吃法</th></tr></thead><tbody><tr><td style="text-align:left;">生姜</td><td style="text-align:left;">温中散寒</td><td style="text-align:left;">晨起姜枣茶</td></tr><tr><td style="text-align:left;">羊肉</td><td style="text-align:left;">温补肾阳</td><td style="text-align:left;">当归生姜羊肉汤</td></tr><tr><td style="text-align:left;">肉桂</td><td style="text-align:left;">引火归原</td><td style="text-align:left;">煮水或入粥</td></tr><tr><td style="text-align:left;">薏米</td><td style="text-align:left;">健脾祛湿</td><td style="text-align:left;">炒薏米煮粥（理中培土粥）</td></tr><tr><td style="text-align:left;">山药</td><td style="text-align:left;">补脾养肺</td><td style="text-align:left;">清蒸或煮粥</td></tr><tr><td style="text-align:left;">黑豆</td><td style="text-align:left;">补肾利湿</td><td style="text-align:left;">煮水或打豆浆</td></tr></tbody></table><h3 id="普明-中虚血虚-特别推荐" tabindex="-1">普明（中虚血虚）特别推荐 <a class="header-anchor" href="#普明-中虚血虚-特别推荐" aria-label="Permalink to &quot;普明（中虚血虚）特别推荐&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">食材</th><th style="text-align:left;">功效</th><th style="text-align:left;">建议吃法</th></tr></thead><tbody><tr><td style="text-align:left;">小米</td><td style="text-align:left;">养胃和中</td><td style="text-align:left;">小米粥</td></tr><tr><td style="text-align:left;">红枣</td><td style="text-align:left;">补气养血</td><td style="text-align:left;">煮水或蒸食</td></tr><tr><td style="text-align:left;">红小豆</td><td style="text-align:left;">养血利水</td><td style="text-align:left;">赤小豆薏米粥</td></tr><tr><td style="text-align:left;">桂圆</td><td style="text-align:left;">养心安神</td><td style="text-align:left;">泡茶或煮粥</td></tr><tr><td style="text-align:left;">黑芝麻</td><td style="text-align:left;">补肝肾乌发</td><td style="text-align:left;">打粉冲服</td></tr><tr><td style="text-align:left;">鸡蛋</td><td style="text-align:left;">补血养阴（素食者关键营养）</td><td style="text-align:left;">每日1-2个</td></tr></tbody></table><hr><p><em>本条目为精简框架版。可扩展至四季养生、二十四节气饮食等专题。</em></p>',36)])])}const c=l(i,[["render",o]]);export{x as __pageData,c as default};
